def is_woodall(n: int) -> bool:
    """
    Check if the number is a Woodall number.
    A Woodall number is defined as W_n = n * 2^n - 1 for some integer n >= 1.
    """
    if n <= 0:
        return False
    # Iterate over possible exponents k starting from 1
    k = 1
    while True:
        candidate = k * (2 ** k) - 1
        if candidate == n:
            return True
        if candidate > n:
            return False
        k += 1

def is_woodall(n: int) -> bool:
    """
