def is_samepatterns(patterns: list, pattern_map: list) -> bool:
    """
    Check if the strings in 'patterns' follow the same substitution pattern as 'pattern_map'.

    Each character in 'pattern_map' must map to a unique string in 'patterns',
    and vice versa (bijection).

    Example:
        is_samepatterns(["red", "green", "green"], ["a", "b", "b"]) -> True
        is_samepatterns(["red", "green", "blue"], ["a", "b", "b"]) -> False
    """
    if len(patterns) != len(pattern_map):
        return False

    mapping = {}
    reverse_mapping = {}

    for p_char, word in zip(pattern_map, patterns):
        if p_char in mapping:
            if mapping[p_char] != word:
                return False
        else:
            if word in reverse_mapping:
                return False
            mapping[p_char] = word
            reverse_mapping[word] = p_char

    return True

