        if p in pattern_to_string:
            if pattern_to_string[p] != s:
                return False
        else:
            if s in string_to_pattern:
                return False
            pattern_to_string[p] = s
            string_to_pattern[s] = p

    return True

def is_samepatterns(patterns: list, pattern_map: list) -> bool:
    """
    Check if the list of strings 'patterns' follows the sequence given in 'pattern_map'.

    This means that every time a string appears in 'patterns', it must map to the same
    character in 'pattern_map', and vice versa.

    Example:
        is_samepatterns(["red", "green", "green"], ["a", "b", "b"]) -> True
        is_samepatterns(["red", "green", "blue"], ["a", "b", "c"]) -> True
        is_samepatterns(["red", "green", "green"], ["a", "b", "c"]) -> False
    """
    if len(patterns) != len(pattern_map):
        return False

    mapping = {}
    reverse_mapping = {}

    for p_str, p_char in zip(patterns, pattern_map):
        if p_str in mapping:
            if mapping[p_str] != p_char:
                return False
        else:
            mapping[p_str] = p_char

        if p_char in reverse_mapping:
            if reverse_mapping[p_char] != p_str:
                return False
        else:
            reverse_mapping[p_char] = p_str

    return True

