def search(arr):
    """
    Finds the element that appears only once in a sorted array.
    Assumes there is exactly one such element.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # If mid is even, compare mid and mid+1
        # If mid is odd, compare mid and mid-1
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                # The unique element is in the right half
                left = mid + 2
            else:
                # The unique element is in the left half (including mid)
                right = mid
        else:
            if arr[mid] == arr[mid - 1]:
                # The unique element is in the left half (including mid)
                right = mid
            else:
                # The unique element is in the right half
                left = mid + 2

    return arr[left]

