    Args:
        arr (List[int]): A sorted list of integers where exactly one element appears once.

    Returns:
        int: The unique element in the array.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is even or odd to compare with neighbors
        if mid % 2 == 0:
            # If current element is same as next, the unique element is to the right
            if arr[mid] == arr[mid + 1]:
                left = mid + 2
            else:
                right = mid
        else:
            # If current element is same as previous, the unique element is to the right
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid - 1

    return arr[left]

