def find_solution(a, b, n):
    if n == 0:
        return (0, 0)

    def extended_gcd(x, y):
        if x == 0:
            return y, 0, 1
        else:
            g, y1, x1 = extended_gcd(y, x % y)
            return g, x1, y1 - (x // y) * x1

    g, x0, y0 = extended_gcd(a, b)

    if n % g != 0:
        return None

    # Scale the solution to match n
    factor = n // g
    x = x0 * factor
    y = y0 * factor

    return (x, y)

import math

def area_polygon(n, s):
    """
    Calculate the area of a regular polygon given the number of sides (n)
    and the length of each side (s).

    Formula: Area = (n * s^2) / (4 * tan(pi / n))
    """
    if n <= 2:
        raise ValueError("Number of sides must be greater than 2")
    if s < 0:
        raise ValueError("Side length must be non-negative")

    return (n * s ** 2) / (4 * math.tan(math.pi / n))

def are_equivalent(a: int, b: int) -> bool:
    def sum_divisors(n: int) -> int:
        if n <= 0:
            return 0
        total = 1  # 1 is a divisor for all positive integers
        for i in range(2, int(n ** 0.5) + 1):
            if n % i == 0:
                total += i
                if i != n // i:
                    total += n // i
        return total

    return sum_divisors(a) == sum_divisors(b)

