def is_majority(arr, n, element):
    if n == 0:
        return False

    # Find first occurrence
    left = 0
    right = n - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] < element:
            left = mid + 1
        elif arr[mid] > element:
            right = mid - 1
        else:
            # Found element, now find first occurrence
            break
    else:
        return False  # Element not found

    first = left
    while first > 0 and arr[first - 1] == element:
        first -= 1

    # Find last occurrence
    last = n - 1
    while last < n - 1 and arr[last + 1] == element:
        last += 1

    count = last - first + 1
    return count > n // 2

def is_majority(arr, n, element):
    if n == 0:
        return False

    # Find the first occurrence of the element
    left = 0
    right = n - 1

    # Binary search for the first occurrence
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] < element:
            left = mid + 1
        elif arr[mid] > element:
            right = mid - 1
        else:
            # Found the element, now find the first occurrence
            break
    else:
        return False  # Element not found

    first_occurrence = left
    if arr[first_occurrence] != element:
        return False  # Should not happen if loop above breaks correctly, but for safety

    # Find the last occurrence
    left = first_occurrence
    right = n - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] < element:
            left = mid + 1
        elif arr[mid] > element:
            right = mid - 1
        else:
            # Found the element, now find the last occurrence
            break
    else:
        return False  # Should not happen if loop above breaks correctly

    last_occurrence = right

    # Count occurrences
    count = last_occurrence - first_occurrence + 1

    return count > n // 2

def is_majority(arr, n, element):
    if n == 0:
        return False

    # Since the array is sorted, find the first and last occurrence of the element
    left = arr.lower_bound(element)
    if left == -1:
        return False

    right = arr.upper_bound(element) - 1

    # Count occurrences
    count = right - left + 1

    return count > n // 2


def lower_bound(arr, target):
    """Returns the first index where arr[index] >= target, or -1 if not found."""
    left, right = 0, len(arr)
    while left < right:
        mid = (left + right) // 2
        if arr[mid] < target:
            left = mid + 1
        else:
            right = mid
    return left if left < len(arr) and arr[left] == target else -1


def upper_bound(arr, target):
    """Returns the first index where arr[index] > target."""
    left, right = 0, len(arr)
    while left < right:
        mid = (left + right) // 2
        if arr[mid] <= target:
            left = mid + 1
        else:
            right = mid
    return left

def is_majority(arr, n, element):
    if n == 0:
        return False

    # In a sorted array, if an element is a majority (> n/2 occurrences),
    # it must appear in the middle region. Specifically, it must start
    # at index <= n//2 and end at index >= n - n//2.
    # We can use binary search to find the first and last occurrence.

    def find_first():
        left, right = 0, n - 1
        result = n  # default if not found
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == element:
                result = mid
                right = mid - 1
            elif arr[mid] < element:
                left = mid + 1
            else:
                right = mid - 1
        return result

    def find_last():
        left, right = 0, n - 1
        result = -1  # default if not found
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == element:
                result = mid
                left = mid + 1
            elif arr[mid] < element:
                left = mid + 1
            else:
                right = mid - 1
        return result

    first = find_first()
    if first == n:
        return False  # element not found

    last = find_last()
    count = last - first + 1

    return count > n // 2

def count_Set_Bits(n):
