def is_octagonal(s):
    """
    Count substrings where the sum of digits equals the length of the substring.
    """
    if not s:
        return 0

    n = len(s)
    count = 0

    for i in range(n):
        for j in range(i + 1, n + 1):
            substring = s[i:j]
            length = len(substring)
            digit_sum = sum(int(digit) for digit in substring)

            if digit_sum == length:
                count += 1

    return count

