def find_unique_element(arr):
    """
    Find the element that appears only once in a sorted array where 
    all other elements appear exactly twice.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2
        # Check if mid is at an even position
        if mid % 2 == 0:
            # Compare with next element
            if arr[mid] == arr[mid + 1]:
                # Unique element is to the right
                left = mid + 2
            else:
                # Unique element is at mid or to the left
                right = mid
        else:
            # Check if mid-1 is at an even position
            if arr[mid] == arr[mid - 1]:
                # Unique element is to the left
                right = mid - 1
            else:
                # Unique element is at mid
                return arr[mid]

    return arr[left]

