def magic_square_test(matrix):
    n = len(matrix)

    # Check if matrix is square
    if len(matrix[0]) != n:
        return False

    # Calculate the expected sum from the first row
    expected_sum = sum(matrix[0])

    # Check if all rows have the same sum
    for row in matrix:
        if sum(row) != expected_sum:
            return False

    # Check if all columns have the same sum
    for col in range(n):
        col_sum = sum(matrix[row][col] for row in range(n))
        if col_sum != expected_sum:
            return False

    # Check if both diagonals have the same sum
    main_diagonal = sum(matrix[i][i] for i in range(n))
    anti_diagonal = sum(matrix[i][n-1-i] for i in range(n))

    if main_diagonal != expected_sum or anti_diagonal != expected_sum:
        return False

    return True

