def pancake_sort(arr):
    n = len(arr)
    for i in range(n):
        max_idx = i
        for j in range(i + 1, n):
            if arr[j] > arr[max_idx]:
                max_idx = j
        if max_idx != i:
            # Flip to bring max to position i
            arr = arr[:max_idx + 1][::-1] + arr[max_idx + 1:]
            arr = arr[:i + 1][::-1] + arr[i + 1:]
    return arr

def pancake_sort(lst):
    """Sort a list using the pancake sorting algorithm."""
    n = len(lst)
    if n <= 1:
        return lst

    for size in range(n, 1, -1):
        max_idx = lst.index(max(lst[:size]))
        if max_idx != size - 1:
            # Flip to bring max to front
            lst = lst[:max_idx + 1] + lst[:max_idx + 1][::-1] + lst[max_idx + 1:]
            # Flip to move max to correct position
            lst = lst[:size] + lst[:size][::-1]
    return lst

