def find_solution(a, b, n):
    """
    Find integers x and y such that ax + by = n.

    Returns None if no solution exists.
    Otherwise returns a tuple (x, y).
    """
    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)

    # Extended Euclidean Algorithm to find gcd and coefficients
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        else:
            g, y, x = extended_gcd(b % a, a)
            return g, x - (b // a) * y, y

    g, x0, y0 = extended_gcd(a, b)

    # Check if solution exists
    if n % g != 0:
        return None

    # Scale the solution
    x = x0 * (n // g)
    y = y0 * (n // g)

    return (x, y)

def find_solution(a, b, n):
    """
    Find integer solutions (x, y) to the linear Diophantine equation ax + by = n.

    Returns:
        tuple: (x, y) if a solution exists, None otherwise
    """
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        else:
            gcd, x1, y1 = extended_gcd(b % a, a)
            return gcd, y1 - (b // a) * x1, x1

    gcd, x, y = extended_gcd(a, b)

    if n % gcd != 0:
        return None

    # Scale the solution to satisfy ax + by = n
    return (x * (n // gcd), y * (n // gcd))

