def is_majority(arr, n, element):
    # Binary search to find first occurrence of element
    left = 0
    right = n - 1
    first = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            first = mid
            right = mid - 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    if first == -1:
        return False

    # Find last occurrence of element
    left = 0
    right = n - 1
    last = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            last = mid
            left = mid + 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

