def bell_number(n):
    """
    Calculate the nth Bell number, which represents the number of ways 
    to partition a set of n elements.
    """
    if n < 0:
        return 0

    # Initialize Bell triangle
    bell_triangle = [[0] * (n + 1)]

    # Fill the Bell triangle
    for i in range(1, n + 1):
        row = bell_triangle[i]
        for j in range(1, i + 1):
            if j == 1:
                row[j] = bell_triangle[i - 1][j - 1]
            else:
                row[j] = row[j - 1] + bell_triangle[i - 1][j]

    return bell_triangle[n][n]

