def is_Monotonic(arr):
    if len(arr) <= 1:
        return True

    # Check if non-decreasing (each element >= previous)
    non_decreasing = True
    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            non_decreasing = False
            break

    # Check if non-increasing (each element <= previous)
    non_increasing = True
    for i in range(len(arr) - 1):
        if arr[i] < arr[i + 1]:
            non_increasing = False
            break

    return non_decreasing or non_increasing

