def eulerian_num(n, m):
    if n < 0 or m < 0 or m > n:
        return 0

    if n == 0:
        return 1

    # Initialize DP table
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    # Fill the DP table using recurrence relation
    for i in range(1, n + 1):
        for j in range(i + 1):
            dp[i][j] = (i - j) * dp[i - 1][j - 1] + (j + 1) * dp[i - 1][j]

    return dp[n][m]

