def search(nums):
    if not nums:
        return None

    # Binary search approach for O(log n) time complexity
    left, right = 0, len(nums) - 1

    while left < right:
        mid = (left + right) // 2

        # If mid is even, it's the start of a pair (or unique)
        # If mid is odd, it's the end of a pair
        if mid % 2 == 0:
            if nums[mid] == nums[mid + 1]:
                # Pair starts at mid, so unique element is to the right
                left = mid + 2
            else:
                # Pair starts at mid + 1, so unique element is at mid or to the left
                right = mid
        else:
            # mid is odd, so it's the end of a pair
            if nums[mid] == nums[mid - 1]:
                # Pair ends at mid, so unique element is to the right
                left = mid + 1
            else:
                # Pair ends at mid - 1, so unique element is at mid or to the left
                right = mid

    return nums[left]

