    while low < high:
        mid = (low + high) // 2

        # If mid is even, check if the element at mid is the same as mid + 1
        # If mid is odd, check if the element at mid is the same as mid - 1
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                # The unique element must be to the right
                low = mid + 2
            else:
                # The unique element is to the left (or mid itself)
                high = mid
        else:
            if arr[mid] == arr[mid - 1]:
                # The unique element must be to the right
                low = mid + 1
            else:
                # The unique element is to the left (or mid itself)
