    A woodall number is a number of the form:
    (2^p - 1) / (p + 1) where p is a prime number.
    """
    if n <= 0:
        return False

    # Check all primes p such that (2^p - 1) / (p + 1) = n
    # This means 2^p - 1 = n * (p + 1)

    # Start with small primes and work upward
    p = 2
    while True:
        # Check if p is prime
        is_prime = True
        if p < 2:
            is_prime = False
        else:
            for i in range(2, int(p**0.5) + 1):
                if p % i == 0:
                    is_prime = False
                    break

        if not is_prime:
            p += 1
            continue

        # Calculate woodall number for this prime
        woodall_num = (2**p - 1) // (p + 1)

        if woodall_num == n:
            return True
        elif woodall_num > n:
            return False

        # Safety check to prevent infinite loop
        if woodall_num > n + 1000:
            return False

        p += 1

