    """Sort a list of elements using the comb sort algorithm."""
    if not lst:
        return lst

    n = len(lst)
    gap = n
    shrink_factor = 1.3

    while gap > 1 or not is_sorted(lst):
        gap = int(gap / shrink_factor)
        if gap < 1:
            gap = 1

        for i in range(n - gap):
            if lst[i] > lst[i + gap]:
                lst[i], lst[i + gap] = lst[i + gap], lst[i]

    return lst

