def binary_search(arr, n, element, find_first):
    """
    Binary search to find the first or last occurrence of element in sorted array.
    """
    left, right = 0, n - 1
    result = -1

    while left <= right:
        mid = (left + right) // 2

        if arr[mid] == element:
            result = mid
            if find_first:
                right = mid - 1
            else:
                left = mid + 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    return result

